class Solution:
    def validatePortMappings(self, services) -> any:
        # Initialize an empty set to store unique port mappings
        port_set = set()
        # Iterate over each service's port mappings
        for service in services:
            # Iterate over each port mapping
            for port in services[service].ports:
                # Check if the container port is valid (i.e., not negative)
                if port.container_port < 0:
                    # Return false if the container port is invalid
                    return False
                # Check if the host port is valid (i.e., not negative)
                if port.host_port < 0:
                    # Return false if the host port is invalid
                    return False
                # Check for duplicate port mappings within a service
                if f'{port.container_port},{port.host_port}' in port_set:
                    # Return false if a duplicate port mapping is found
                    return False
                # Add the port mapping to the set
                port_set.add(f'{port.container_port},{port.host_port}')
        # Iterate over each service's port mappings again to check for port collisions
        for service in services:
            # Iterate over each port mapping
            for port in services[service].ports:
                # Iterate over each other service's port mappings
                for otherService in services:
                    # Skip if the other service is the same as the current service
                    if service == otherService:
                        continue
                    # Check if the host port of the current port mapping matches any other service's host port
                    for otherPort in services[otherService].ports:
                        if port.host_port == otherPort.host_port:
                            # Return false if a port collision is found
                            return False
        # Return true if all port mappings are valid
        return True
return Solution().validatePortMappings
